INSERT INTO restaurant_maintenancelog (date, work_performed, performed_by, signature, created_at)
VALUES
('2026-05-01', 'Плановое обслуживание серверного оборудования. Проверка работоспособности всех модулей системы АИС «Общепит». Обновление программного обеспечения до актуальной версии.', 'Дубровин КС', '', NOW()),
('2026-05-03', 'Резервное копирование базы данных PostgreSQL. Проверка целостности данных. Оптимизация индексов таблиц restaurant_order и restaurant_orderitem.', 'Дубровин КС', '', NOW()),
('2026-05-06', 'Обновление зависимостей проекта: Django 4.2.7, psycopg2-binary, dj-database-url. Проверка совместимости компонентов. Тестирование основных функций системы.', 'Дубровин КС', '', NOW()),
('2026-05-08', 'Добавление моделей ActionLog и LoginAttempt для обеспечения безопасности. Выполнение миграций базы данных. Тестирование журналирования действий пользователей.', 'Дубровин КС', '', NOW()),
('2026-05-10', 'Настройка системы резервного копирования. Интеграция с сервисом cron-job.org для автоматических ежедневных резервных копий PostgreSQL через pg_dump.', 'Дубровин КС', '', NOW()),
('2026-05-13', 'Исправление ошибки дублирования ключей (duplicate key) в таблицах БД. Сброс sequence счётчиков через setval. Проверка корректности работы заказов.', 'Дубровин КС', '', NOW()),
('2026-05-15', 'Обновление интерфейса панели администратора. Переработка шаблонов Django Admin для соответствия единому стилю сайта. Тестирование адаптивности.', 'Дубровин КС', '', NOW()),
('2026-05-17', 'Реализация системы блокировки учётных записей после 5 неудачных попыток входа. Добавление возможности разблокировки администратором. Тестирование безопасности.', 'Дубровин КС', '', NOW()),
('2026-05-20', 'Исправление отображения времени у официанта и повара. Устранение сдвига на 5 часов из-за разницы UTC/локального времени. Обновление функции addHours().', 'Дубровин КС', '', NOW()),
('2026-05-22', 'Переработка страницы отчётов. Добавление интерактивных графиков Chart.js (комбо: столбцы + линия). Исправление экспорта Excel с учётом выбранного периода.', 'Дубровин КС', '', NOW()),
('2026-05-24', 'Добавление функции генерации чеков. Создание модели Receipt для хранения информации об оплатах. Реализация endpoint для скачивания чеков.', 'Дубровин КС', '', NOW()),
('2026-05-27', 'Устранение ошибки SyntaxError в JavaScript модуля зала ресторана. Замена inline-обработчиков событий на делегированные через data-атрибуты. Тестирование кликов.', 'Дубровин КС', '', NOW()),
('2026-05-29', 'Плановое резервное копирование всех данных системы. Проверка работоспособности всех модулей: зал официанта, кухня, отчёты, журнал ТО, резервное копирование.', 'Дубровин КС', '', NOW());
